insert into public.questions
  (subject_id, lecture_id, tag, stem, option_a, option_b, option_c, option_d, option_e, answer, explanation, image_url)
values
  ('ethics', 'et-09', 'Medical Errors', 'A wrong diagnosis made despite proper evaluation is negligence.', 'True', 'False', '', '', '', 1, 'It is a medical error, not negligence; it can occur even with good intentions and without negligence.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Medical errors always lead to harm.', 'True', 'False', '', '', '', 1, 'Medical errors do not always cause harm (for example, near-misses).', null),
  ('ethics', 'et-09', 'Medical Errors', 'Medical errors always indicate negligence.', 'True', 'False', '', '', '', 1, 'A medical error may occur without negligence.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Medical errors may occur without negligence.', 'True', 'False', '', '', '', 0, 'Errors can happen even with appropriate care and good intentions.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Medical errors are always punishable.', 'True', 'False', '', '', '', 1, 'Not all medical errors are punishable; this depends on whether there was negligence and harm.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Medical errors only occur in surgery.', 'True', 'False', '', '', '', 1, 'Medical errors can occur in any area of practice, not only surgery.', null),
  ('ethics', 'et-09', 'Medical Errors', 'A surgeon operating on the wrong limb of a patient is an example of gross negligence.', 'True', 'False', '', '', '', 0, 'Wrong-site surgery is a classic example of gross negligence.', null),
  ('ethics', 'et-09', 'Medical Errors', 'The situation shown in the image reflects a failure of the surgeon''s responsibility only.', 'True', 'False', '', '', '', 1, 'It reflects a failure of both individual responsibility and system safeguards (e.g., no surgical-site verification or a checklist failure).', 'data:image/jpeg;base64,'),
  ('ethics', 'et-09', 'Medical Errors', 'A doctor who prescribes penicillin to a patient with a documented allergy, causing anaphylaxis, has made a medical error but not negligence.', 'True', 'False', '', '', '', 1, 'It is negligence: the doctor failed to meet the accepted standard of care by not checking or acting on the documented allergy.', null),
  ('ethics', 'et-09', 'Medical Errors', 'A doctor who forgets to order a critical test has committed an error of commission.', 'True', 'False', '', '', '', 1, 'This is an error of omission (failing to do something that should have been done).', null),
  ('ethics', 'et-09', 'Medical Errors', 'A doctor who gives the wrong drug dose has committed an error of commission.', 'True', 'False', '', '', '', 0, 'Giving a wrong dose is an error of commission (doing something incorrectly).', null),
  ('ethics', 'et-09', 'Medical Errors', 'A patient harmed as a result of a wrong surgery is an example of malpractice.', 'True', 'False', '', '', '', 0, 'Harm resulting from substandard care constitutes malpractice.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Diagnostic errors are delayed or wrong diagnoses.', 'True', 'False', '', '', '', 0, 'Diagnostic errors include missed, wrong, or delayed diagnoses.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Treatment errors are the failure to provide prophylaxis.', 'True', 'False', '', '', '', 1, 'Failure to provide prophylaxis is a preventive error.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Preventive errors are giving the wrong drug, dose, or procedure.', 'True', 'False', '', '', '', 1, 'Giving the wrong drug, dose, or procedure is a treatment error.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Communication errors are poor doctor-patient or team communication.', 'True', 'False', '', '', '', 0, 'Communication errors arise from poor communication between the doctor, the patient, or the team.', null),
  ('ethics', 'et-09', 'Medical Errors', 'Medical negligence without harm may become a legal case.', 'True', 'False', '', '', '', 1, 'Malpractice requires medical negligence WITH proven harm; negligence without harm is generally not actionable.', null);
